class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def generateTrees(n: int) -> list[TreeNode]:
    if n == 0:
        return []

    memo = {}

    def _generate(start, end):
        if (start, end) in memo:
            return memo[(start, end)]

        if start > end:
            return [None]

        all_possible_trees = []
        for i in range(start, end + 1):  # i is the current root value
            left_subtrees = _generate(start, i - 1)
            right_subtrees = _generate(i + 1, end)

            for left_tree in left_subtrees:
                for right_tree in right_subtrees:
                    current_root = TreeNode(i)
                    current_root.left = left_tree
                    current_root.right = right_tree
                    all_possible_trees.append(current_root)

        memo[(start, end)] = all_possible_trees
        return all_possible_trees

    return _generate(1, n)
